protocol Identifiable {
    var id: String { get }
}

struct User: Identifiable {
    var id: String
    var name: String
}

let newPlayer = User(id: "#9999", name: "Alice")
print("Welcome \(newPlayer.name) - ID: \(newPlayer.id)")
